using Microsoft.AspNetCore.Mvc; using SchoolEnterprise.Helpers; using SchoolEnterprise.Models.Domain; using SchoolEnterprise.Models.ViewModels; using SchoolEnterprise.Repositories; using SchoolEnterprise.Services;
namespace SchoolEnterprise.Controllers;
[RoleGuard("Admin","Secretary")]
public class StudentsController(StudentRepository students, StudentRecordRepository records, SequenceService seq, AuditService audit, PromotionService promotion) : Controller
{ public IActionResult Index()=>View(students.GetAll()); public IActionResult Details(int id)=>View(students.GetById(id)); [HttpGet] public IActionResult Create()=>View(new StudentCreateVm{AcademicYear="2025/2026"}); [HttpPost] public IActionResult Create(StudentCreateVm vm){ if(students.GetByMinistryCode(vm.MinistryCode)!=null){ModelState.AddModelError("","الكود الوزاري مكرر"); return View(vm);} var s=new StudentRegistration{StudentId=seq.Next("StudentId"),GeneralRegisterNumber=seq.Next("GeneralRegister"),MinistryCode=vm.MinistryCode,FirstName=vm.FirstName,FatherName=vm.FatherName,GrandFatherName=vm.GrandFatherName,LastName=vm.LastName,MotherName=vm.MotherName,BirthDate=vm.BirthDate,Phone=vm.Phone,Address=vm.Address}; students.Add(s); records.Add(new StudentRecord{StudentRecordId=seq.Next("StudentRecordId"),StudentId=s.StudentId,AcademicYear=vm.AcademicYear,Grade=vm.Grade,Section=vm.Section,RollNumber=vm.RollNumber,IsCurrent=true}); audit.Log("إضافة طالب",$"{s.StudentId}"); return RedirectToAction(nameof(Index)); } [HttpGet] public IActionResult Edit(int id){var s=students.GetById(id); if(s==null) return NotFound(); return View(new StudentEditVm{StudentId=s.StudentId,MinistryCode=s.MinistryCode,FirstName=s.FirstName,FatherName=s.FatherName,GrandFatherName=s.GrandFatherName,LastName=s.LastName,MotherName=s.MotherName,BirthDate=s.BirthDate,Phone=s.Phone,Address=s.Address}); } [HttpPost] public IActionResult Edit(StudentEditVm vm){var s=students.GetById(vm.StudentId); if(s==null) return NotFound(); s.MinistryCode=vm.MinistryCode; s.FirstName=vm.FirstName; s.FatherName=vm.FatherName; s.LastName=vm.LastName; s.MotherName=vm.MotherName; s.Phone=vm.Phone; s.Address=vm.Address; students.Update(s); audit.Log("تعديل طالب",$"{s.StudentId}"); return RedirectToAction(nameof(Index)); } public IActionResult Promote(int id){var rec=records.GetCurrentByStudentId(id); if(rec!=null){promotion.Promote(rec,"2026/2027",rec.Grade+"+1"); audit.Log("ترفيع",$"{id}");} return RedirectToAction(nameof(Index)); }}